class MKAverage {
    private int m, k;
    private long sum;
    private TreeMap<Integer, Integer> minTree, midTree, maxTree;
    private Queue<Integer> queue;

    public MKAverage(int m, int k) {
        this.m = m;
        this.k = k;
        minTree = new TreeMap<>();
        midTree = new TreeMap<>();
        maxTree = new TreeMap<>();
        queue = new LinkedList<>();
        sum = 0;
    }

    public void addElement(int num) {
        queue.offer(num);
        if (queue.size() > m) {
            int toRemove = queue.poll();
            if (minTree.containsKey(toRemove)) {
                remove(minTree, toRemove);
            } else if (midTree.containsKey(toRemove)) {
                remove(midTree, toRemove);
                sum -= toRemove;
            } else {
                remove(maxTree, toRemove);
            }
        }
        insert(num);
        if (queue.size() == m) {
            while (minTree.size() > k) {
                int toMove = minTree.lastKey();
                sum += toMove;
                move(minTree, midTree, toMove);
            }
            while (midTree.size() > m - 2 * k) {
                int toMove = midTree.lastKey();
                sum -= toMove;
                move(midTree, maxTree, toMove);
            }
            while (maxTree.size() > k) {
                int toMove = maxTree.firstKey();
                move(maxTree, midTree, toMove);
                sum += toMove;
            }
            while (midTree.size() < m - 2 * k && !maxTree.isEmpty()) {
                int toMove = maxTree.firstKey();
                sum += toMove;
                move(maxTree, midTree, toMove);
            }
            while (midTree.size() < m - 2 * k && !minTree.isEmpty()) {
                int toMove = minTree.lastKey();
                sum += toMove;
                move(minTree, midTree, toMove);
            }
        }
    }

    public int calculateMKAverage() {
        return queue.size() < m ? -1 : (int) (sum / (m - 2 * k));
    }

    private void insert(int num) {
        if (minTree.isEmpty() || num <= minTree.lastKey()) {
            add(minTree, num);
        } else if (maxTree.isEmpty() || num >= maxTree.firstKey()) {
            add(maxTree, num);
        } else {
            add(midTree, num);
            sum += num;
        }
    }

    private void add(TreeMap<Integer, Integer> tree, int num) {
        tree.put(num, tree.getOrDefault(num, 0) + 1);
    }

    private void remove(TreeMap<Integer, Integer> tree, int num) {
        int count = tree.get(num) - 1;
        if (count == 0) {
            tree.remove(num);
        } else {
            tree.put(num, count);
        }
    }

    private void move(TreeMap<Integer, Integer> from, TreeMap<Integer, Integer> to, int num) {
        remove(from, num);
        add(to, num);
    }
}

